kernel void dynproc_kernel(
    int arg0,
    const int* d_gpuWall,
    const int* d_gpuResult_src,
    int* d_gpuResult_dst,
    int cols,
    int rows,
    int t,
    int borderCols,
    int theHalo,
    int* local_min_buffer,
    int* local_src_buffer,
    int* d_outputBuffer)
{
    int gid = get_global_id(0);
    int lid = get_local_id(0);
    int lsize = get_local_size(0);

    if (gid >= cols) return;

    // Load initial source value
    int src_val = d_gpuResult_src[gid];
    local_src_buffer[lid] = src_val;
    local_min_buffer[lid] = src_val;
    barrier(CLK_LOCAL_MEM_FENCE);

    // Compute min over neighbors within the block using local memory
    // We need to consider gid-1 and gid+1 if they exist
    int min_val = src_val;

    if (gid > 0) {
        int left_val = d_gpuResult_src[gid - 1];
        if (left_val < min_val) min_val = left_val;
    }
    if (gid < cols - 1) {
        int right_val = d_gpuResult_src[gid + 1];
        if (right_val < min_val) min_val = right_val;
    }

    d_gpuResult_dst[gid] = d_gpuWall[t * cols + gid] + min_val;
}
